var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nADC FACTOR: <color=#ffd34c>CONFIRMED</color>\\nMN No. FW000P5027: <color=#ffd34c>FWH-35A Titan</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>\\nADC FACTOR：<color=#ffd34c>CONFIRMED</color>\\nMN No. FW000P5027：<color=#ffd34c>FWH-35A Titan</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nADC FACTOR: <color=#ffd34c>CONFIRMED</color>\\nMN No. FW000P5027: <color=#ffd34c>FWH-35A Titan</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nADC FACTOR: <color=#ffd34c>CONFIRMED</color>\\nMN No. FW000P5027: <color=#ffd34c>FWH-35A Titan</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"가장 큰 난관은 역시 하중에 의한 부하겠죠.","JPN":"最大の難関は、やはり荷重による負荷です。","ENG":"The greatest challenge has to be stress from the weight.","TWN":"最大的難關果然還是負荷問題吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"전체 하중은 시뮬레이션을 거쳐서 줄일 대로 줄였어요. 그런데도 예상 부하의 60% 가량을 지지하는 게 한계입니다.","JPN":"全体の荷重はシミュレーションを経て、減らせるだけ減らしました。\\nそれでも、予想負荷の60％以上を支えるのが限界です。","ENG":"We've already reduced the overall weight as much as possible during the simulations. Still, we can only support up to 60% of the estimated load.","TWN":"我們通過模擬儘量減少了總負重。但也只能維持預期負荷的60%。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"젠장, 이럴 거면 기술자들은 뭐 하러 여기 앉혀 놓나?","JPN":"ちくしょう、エンジニアがここにいる意味がない！","ENG":"What's the use of all these engineers then?","TWN":"媽的，技術人員都是幹什麼吃的？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"하나부터 열까지 말도 안 되는 문제만 튀어나오는데.","JPN":"こんな問題を私たちにどうしろって言うんだ！","ENG":"We keep getting these ridiculous problems.","TWN":"就不能讓我聽聽好消息嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"애초에 이족보행병기 같은 걸 만들자는 아이디어는 누가 내놓은 거야?","JPN":"大体、二足歩行兵器を作るなんてアイデアを出したのは誰だ！？","ENG":"Whose idea was it to make a bipedal weapon system in the first place?","TWN":"當初是誰提出要製造人形機甲的？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"누구긴 누구겠습니까. 엠버 소장님이지.","JPN":"アンバー所長に決まってるじゃないですか。","ENG":"Who else? Director Ember.","TWN":"還會是誰。當然是琥珀所長啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"정말이지...... 그 여자는 인공지능만 꽂으면 앉은뱅이가 일어나기라도 할 줄 아는 건가?","JPN":"くそ……あの女は、人工知能さえ搭載すればロボットが立ち上がるとでも思ってるのか？","ENG":"Seriously... That woman probably thinks an A.I. could make the lame walk again.","TWN":"不會吧……那女的不會真的以為只要把人工智慧裝進去，瘸子也能站起來吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"회의 석상에서 말씀이 너무 지나치십니다. 체르노프 교수님.","JPN":"会議中なのに言葉が過ぎますよ。チェルノフ教授。","ENG":"I'd choose my words more carefully at an official meeting if I were you. Professor Chernov.","TWN":"您正坐在會議桌上，請注意自己的發言。切爾諾夫教授。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아, 소, 소장님! 오셨습니까?","JPN":"あ、しょ、所長！","ENG":"Oh, D-Director! I didn't know you were coming...","TWN":"啊，少，少校！您來啦？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"크흠.....!","JPN":"こほん……！","ENG":"Ahem!","TWN":"咳咳……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"구동계 설계가 지지부진하대서 와 봤더니, 아니나 다를까 불평 불만만 늘어놓고 계시네요, 체르노프 교수님.","JPN":"駆動系の設計がうまくいってないという話を聞いて来てみれば……\\nやはり文句ばかり言っておられるんですね、チェルノフ教授。","ENG":"I dropped by to check on the delay with the thruster designs, and what do you know, here I find you doing nothing but complaining, Professor Chernov.","TWN":"我聽說驅動程式設計專案進度緩慢，所以就過來看看。果然您就只是在大肆抱怨呢，切爾諾夫教授。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"이젠 슬슬 인정하실 때도 되지 않았나요?","JPN":"そろそろお認めになってはいかがです？","ENG":"Isn't it about time you admitted it though?","TWN":"現在差不多可以承認了吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"뭐를? 자네의 그 정신 나간 아이디어를?","JPN":"何を認めればいいんだ？　君のその狂ったアイデアか？","ENG":"Admit what? That your idea is absolutely ridiculous?","TWN":"承認什麼？你那愚蠢的主意嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"아니면 관리국 놈들이 주는 엉터리 같은 데이터를?","JPN":"それとも、管理局のやつらが渡してきたでたらめのデータか？","ENG":"Or how worthless the data from the Administration is?","TWN":"還是管理局那群傢伙提供荒唐資料？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"우리가 왜 퓨처 앳 워 계획에 참가했는지 알기는 아나?","JPN":"なぜ私たちが、フューチャーアットウォー計画に参加したか知ってるか？","ENG":"Do you know why we participated in the Future at War Project in the first place?","TWN":"你知道我們為什麼參加天啟兵器計畫嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"저 망할 전쟁 때문에 죽어 나가는 사람이 없게 하기 위해서야!","JPN":"これ以上、あのクソみたいな戦争で、死者を出したくないからだ！","ENG":"It was to make sure no more people die in that blasted war!","TWN":"是為了不讓人們因為那該死的戰爭死去！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"장난감이나 만들자고 전세계 석학들이 이리로 모여든 게 아닐세!","JPN":"おもちゃを作るために、世界中の著名な学者たちが、ここに集まったわけじゃないんだ！","ENG":"We didn't put the world's greatest minds together just to build some toys!","TWN":"世界各地的頂級學者不是為了製作玩具才聚集到這裡的！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L21_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"처음 이면세계 얘기가 나왔을 때도 다들 그런 식으로 반응했죠.","JPN":"裏世界の話が初めて公表された時も、みんな同じような反応でした。","ENG":"That's how everyone reacted when the Counterside discussion first came up too.","TWN":"當初提到異界時，大家都是這種反應。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"적을 알고 나를 알아야 싸움에서 이긴다는데, 우리는 침식체에 대해 아무것도 몰라요.","JPN":"敵を知り、己を知ることで戦いに勝てる。\\nしかし、私たちは侵食体について無知ですから。","ENG":"Like the saying goes, we must know our enemies and ourselves to win, but we don't know a thing about the C.O.s.","TWN":"明明知己知彼才能百戰百勝，但我們對侵蝕體的理解少之又少。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"그러니 조금이라도 승산을 높일 만한 일은 전부 시도해 보는 게 최선이겠죠.","JPN":"だから、少しでも勝算を高められることなら、試すしかないんです。","ENG":"So our best bet is to try everything that may increase our chance of winning.","TWN":"所以，最好可以嘗試所有能提高勝算的方法。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"자네는 정말 가능하다고 믿나? 이게 3종 침식체를 단독으로 격퇴할 수 있다고?","JPN":"君は本当に可能だと信じているのか？\\nこれが、第3種侵食体を単独で撃退できると？","ENG":"Do you really believe it's possible? This thing can defeat a Category 3 C.O. all by itself?","TWN":"你們真的相信嗎？真的相信這個武器可以獨自擊退3類侵蝕體？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"도시 하나를 쑥대밭으로 만든...... 그 괴물을 말이야.","JPN":"都市をまるごと廃墟にした……あの化け物を？","ENG":"I'm talking about that monster... that mowed down an entire city.","TWN":"而且是那個……把一座城市都變成廢墟的怪物。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"물론입니다.","JPN":"もちろんです。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"전술통제용 강인공지능의 성장에 따라서는 그 이상의 결과도 기대하고 있습니다.","JPN":"戦術統制用の人工知能が成長するにつれ、\\nそれ以上の結果を出すことも期待しています。","ENG":"We have even higher expectations pending the machine learning progress of the strong A.I. for tactical control.","TWN":"而且根據上述戰略操作高度人工智慧的成長，我們也期待它能有更好的成果。 "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"그 이상이라면...... 설마 4종......?","JPN":"それ以上……まさか、第4種のことか……？","ENG":"Even higher? You don't mean... Category 4?","TWN":"更好的……難道是4類……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"거기까지는 제게도 아직 기대의 영역이라고 해 두죠.","JPN":"私にとっても、それはまだ期待の領域ですが。","ENG":"Let's just say that's still in the realm of hope, even for me.","TWN":"到目前為止，它也還停留在期待的階段。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"지금처럼 포격전 전용이 아니라, 발굴된 원본처럼 백병전이 가능한 버전의 메인프레임을 복구할 수 있다면......","JPN":"現在のように砲撃戦専用ではなく、発掘された原型のように\\n白兵戦が可能なバージョンのメインフレームを復旧できれば……","ENG":"If we could only restore the melee-capable main frame of the excavated original, as opposed to the current artillery model…","TWN":"像挖掘到的原型，它的主機是可以進行混戰的版本，只要能夠修復那個主機，就可以不局限於砲擊戰……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"좀 더 희망적인 분위기를 만들어 보죠. 흥미로운 소식을 하나 전해 드리겠습니다.","JPN":"もう少し明るい雰囲気を作りましょうか。皆さんに一つ、興味深いお知らせを。","ENG":"How about we change the subject to something more optimistic? I've got some interesting news for you.","TWN":"為了讓各位對這件事抱有更大的希望，我這裡一個很有趣的消息。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"조선소의 인부들이 차원 함선 건조 중에 신기한 현상을 목격했습니다.","JPN":"造船所の職人たちが次元艦船を建造している途中、不思議な現象を目撃しました。","ENG":"The workers at the shipyard witnessed an amazing phenomenon while constructing the dimension ship.","TWN":"造船廠的工人在建造次元艦船時，目睹了一個奇怪的現象。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"이터니움 드라이브의 시험 가동을 마친 후, 근처에 있던 공구 따위가 공중에서 둥둥 떠다녔다고 하더군요.","JPN":"エタニウムドライブのテスト稼働を終えた後、近くにあった工具が宙に浮いたそうです。","ENG":"When they finished the test run of the Eternium drive, they saw tools levitating nearby.","TWN":"據說永恆之金引擎的啟動測試結束後，周圍的工具都在空中到處亂飛。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"......가동 후에도 말인가? 반중력장이 이터니움 드라이브 주위에 잔류한다고?","JPN":"……稼働後にも？　反重力場がエタニウムドライブの周りに残留したというのか？","ENG":"Even after the drive was shut down? You mean there was a residual anti-gravity field around the Eternium drive?","TWN":"……啟動後也是嗎？你是說反重力場殘留在永恆之金引擎周圍？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"그게 말이 되나? 우리 쪽 연구소에서 시험할 땐 아무런 특이사항이 없었는데?","JPN":"あり得ない！　私たちが研究所でテストした時、特異事項は何もなかった！","ENG":"Is that even possible? We didn't see any anomalies like that when we ran the tests in our lab!","TWN":"這怎麼可能？我們在研究所測試時，可從沒有過任何異常現象啊？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"1세대에 비해 출력이 높아졌기 때문이겠죠. 일단 관리국에선 그렇답니다.","JPN":"第1世代に比べて出力が高くなったからでしょう。とりあえず、管理局はそう言ってました。","ENG":"It's probably because the output is greatly increased compared to the first generation. Anyway, that's what the Administration is telling us.","TWN":"是因為它比第一代功率高吧？總之管理局是這麼說的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"......그래. 관리국 놈들은 매번 그런 식으로 둘러대지.","JPN":"……ああ。管理局のやつらは、いつもそうやって適当にごまかすんだ。","ENG":"I see... Well, those jerks at the Administration always come up with an excuse like that.","TWN":"……是嗎？管理局的傢伙每次不都這樣敷衍過去的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"그래서 뭐, 잔류 반중력장으로 하중을 지지하자고?","JPN":"それで、何だ？　残留する反重力場で荷重を支えろとでも言いたいのか？","ENG":"So what's your point? You want to use the residual anti-gravity field to offset the weight?","TWN":"那你要怎麼做，想利用反重力場支撐負重嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"그건 이제부터 교수님이 해결할 문제죠. 제 전공 분야는 인공지능입니다.","JPN":"それは、これから教授が解決すべき問題です。私の専攻分野は人工知能なので。","ENG":"That's what you need to figure out from now on. My specialty is in artificial intelligence.","TWN":"這個問題現在就交給教授解決了。我的專攻領域是人工智慧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"그 남일 아니라는 식의 태도는 대학원 때부터 바뀐 게 없구만.","JPN":"その他人行儀な態度は、大学院の時から変わりないな。","ENG":"You haven't changed a bit since grad school, have you? Never willing to lift a finger for others.","TWN":"你這事不關己的態度，真是從研究生時期開始就沒變過啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"하지만 정말로 국소적으로나마 반중력장을 유지시킬 수 있다면......","JPN":"だが、もし本当に局所的にでも、反重力場を維持できれば……","ENG":"On a more serious note, if we can maintain the anti-gravity field even at trace levels...","TWN":"不過，要是真有辦法維持局部的反重力場……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_RECORD","text":{"KOREA":"담당 연구진들과 회의 일정을 잡아야겠네. 자네는 냉큼 여기서 나가게.","JPN":"担当研究チームとの会議を調整しなくては。君は早くここから出たまえ。","ENG":"I'm going to have to set a meeting with the research team. See yourself out of here, pronto.","TWN":"我得安排一下研究小組的會議日程了。你馬上出去。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"건투를 빌겠습니다. 교수님.","JPN":"ご健闘を祈ります、教授。","ENG":"I wish you the best of luck. Professor.","TWN":"祝您好運。教授。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EMBER_NPC_NULL_NULL","text":{"KOREA":"북극점 작전이 코앞이니까요.","JPN":"北極点作戦が目の前ですから。","ENG":"We'll need it, since Operation North Pole is right around the bend.","TWN":"畢竟北極點作戰馬上就要開始了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};